import React, { useState } from 'react';
import axios from 'axios';

const Chat = () => {
    const [input, setInput] = useState("");
    const [messages, setMessages] = useState([]);
    const [loading, setLoading] = useState(false);

    const handleSendMessage = async () => {
        if (!input.trim()) return;

        const userMessage = { text: input, sender: "user" };
        setMessages([...messages, userMessage]);
        setInput("");
        setLoading(true);

        try {
            // FIX: Ensure the key is "question" to match your backend GraphState
            const response = await axios.post("http://127.0.0.1:8000/chat", {
                question: input 
            }, {
                timeout: 15000 // 15 seconds timeout for slow AI responses
            });

            const aiMessage = { text: response.data.answer, sender: "ai" };
            setMessages((prev) => [...prev, aiMessage]);
        } catch (error) {
            console.error("Chat Error:", error);
            let errorMessage = "Network Error: Is the backend server running on port 8000?";
            
            if (error.response) {
                errorMessage = `Server Error: ${error.response.data.detail || "Unknown error"}`;
            }
            
            setMessages((prev) => [...prev, { text: errorMessage, sender: "ai" }]);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ maxWidth: "600px", margin: "50px auto", padding: "20px", border: "1px solid #ccc", borderRadius: "10px" }}>
            <h2>Resume AI Chat</h2>
            <div style={{ height: "400px", overflowY: "auto", border: "1px solid #eee", padding: "10px", marginBottom: "10px" }}>
                {messages.map((msg, index) => (
                    <div key={index} style={{ textAlign: msg.sender === "user" ? "right" : "left", margin: "10px 0" }}>
                        <span style={{ background: msg.sender === "user" ? "#007bff" : "#e9ecef", color: msg.sender === "user" ? "white" : "black", padding: "8px 12px", borderRadius: "15px" }}>
                            {msg.text}
                        </span>
                    </div>
                ))}
                {loading && <p>AI is thinking...</p>}
            </div>
            <div style={{ display: "flex" }}>
                <input 
                    type="text" 
                    value={input} 
                    onChange={(e) => setInput(e.target.value)} 
                    onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                    style={{ flex: 1, padding: "10px" }}
                    placeholder="Ask about the resume..."
                />
                <button onClick={handleSendMessage} style={{ padding: "10px 20px", cursor: "pointer" }} disabled={loading}>
                    Send
                </button>
            </div>
        </div>
    );
};

export default Chat;
